from flask import redirect, session

def login_redirect():
    """
    Redirects users to their intended destination after authentication.

    Returns:
        A redirect response to the user's intended destination.
    """

    # Get the user's intended destination from the session.
    next_page = session.get('next_page')

    # If the user's destination is set, redirect them there.
    if next_page:
        return redirect(next_page)

    # Otherwise, redirect them to the home page.
    return redirect('/')